import React from 'react';
import {
    Container, Table, Modal, Row, Col,
    Button,
    Pagination,
    // Button, Modal, Row, Col, FormControl, InputGroup, ButtonGroup,
} from 'react-bootstrap';

import PropTypes from 'prop-types';
import ReactHTMLTableToExcel from 'react-html-table-to-excel';
import logo from "../logo.png";

// import "./report-styles.css";    // If we use HTML to Excel, CSS style won't work. Must use inline style.
import { DataContext } from '../data-context.js';
import moment from 'moment'; // https://momentjs.com/
import { css } from '@emotion/core';
import GridLoader from 'react-spinners/GridLoader'; // https://www.react-spinners.com/

const util = require('../util.js');
const override = css`
    display: block;
    margin: 0 auto;
    border-color: red;
`;

// const styleAllBorders = css`
//     border: thin solid black;
//     text-align: center
// `;

// const _cssCirlcle = css`
//     background: #f00;
//     width: 200px;
//     height: 200px;
//     border-radius: 50%;
//     `;

const cssCirlcle = {
    // background: '#f00',
    border: 'thin solid #000',
    width: '20px',
    height: '20px',
    borderRadius: '50%'
};

const styleAllBorders = {
    border: 'thin solid #000',
    textAlign: 'center'
}

const styleNoBorders = {
    border: 'none',
    textAlign: 'center'
}
export default class KPIReport extends React.Component {
    static contextType = DataContext;
    static propTypes = {
        startDate: PropTypes.object.isRequired,
        endDate: PropTypes.object.isRequired,
        onClose: PropTypes.func,
        perPage: PropTypes.number

    };

    data = {};
    vendors = [];
    vendorMap = {};

    users = [];
    userMap = {};
    limit = 0;

    constructor(...args) {
        super(...args);

        this.state = {
            startDate: this.props.startDate,
            endDate: this.props.endDate,
            loading: false,
        }

        console.log('DailyReport', this.state)


        this.handleKeyDown = this.handleKeyDown.bind(this);
    }

    handleKeyDown = function (event) {
        switch (event.keyCode) {
            case 27:
                this.props.onClose()
                break;
            default:
                break;
        }

    }


    // UNSAFE_componentWillReceiveProps() {
    UNSAFE_componentWillMount() {
        // static getDerivedStateFromProps(props, state) {
        console.log('UNSAFE_componentWillReceiveProps fetchJobsByRange', this.props.startDate, this.props.endDate)
        // this.fetchjobs();

        document.addEventListener("keydown", this.handleKeyDown);
        this.setState(
            { loading: true },
            () => util.fetchJobsByRange(this.state.startDate, this.state.endDate)
                .then(res => {
                    let totalPages = Math.ceil(res.data.length / this.props.perPage)
                    this.setState({
                        jobs: res.data,
                        loading: false,
                        currentPage: totalPages > 1 ? 1 : 0
                    })
                })
        )
    }

    // fetchjobs() {
    //     util.fetchjobs(this.state.part._id,
    //         (res) => {
    //             console.log('fetchTransaction', res);
    //             this.setState({
    //                 jobs: res.data
    //             });
    //         },
    //         (err) => {
    //             console.error(err);
    //         }, this.limit);
    // }


    handlePageClick = data => {
        let selected = data.selected;
        let offset = Math.ceil(selected * this.props.perPage);

        this.setState({ offset: offset }, () => {
            // this.loadCommentsFromServer();
        });
    };

    render() {
        // let part = this.props.part;
        // let users = this.state.users;
        // console.log('part', part)

        /* show={this.state.showDatePickerForm} */
        // console.log('jobs', this.state.jobs);
        if (this.state.loading) {
            return (
                <Container className="d-flex align-items-center" fluid style={{ backgroundColor: '#ffffff', minHeight: '100vh' }}>
                    <GridLoader
                        css={override}
                        sizeUnit={"px"}
                        size={80}
                        color={'#4A90E2'}
                        loading={this.props.loading}
                    />

                </Container>
            )
        }
        if (!this.state.jobs || this.state.jobs.length === 0) {
            return (
                <Modal
                    show={true}
                    onHide={this.props.onClose}
                    size="lg"
                    aria-labelledby="contained-modal-title-vcenter"
                    keyboard>
                    <Modal.Header closeButton>
                        <Modal.Title>Daily Report</Modal.Title>
                    </Modal.Header>
                    <Modal.Body>
                        <h3>ไม่มีข้อมูลในช่วงเวลาที่เลือก</h3>
                        <p>
                            {/* <h2>No Data on {this.props.startDate}</h2> */}
                            {moment(this.state.startDate).format('DD-MM-YYYY HH:mm')} - {moment(this.state.endDate).format('DD-MM-YYYY HH:mm')}
                        </p>
                    </Modal.Body>
                    <Modal.Footer>
                        <Button onClick={this.props.onClose}>Close</Button>
                    </Modal.Footer>
                </Modal>
            )
        }

        let jobs = this.state.jobs.map((v, i) => {

            return (
                <tr style={{ height: '40px' }} key={i + 1}>


                    <td style={styleAllBorders}>{v.code}</td>
                    <td style={styleAllBorders}>{v.line_name}</td>
                    <td style={styleAllBorders}>{v.machine_code}</td>
                    <td style={styleAllBorders}>{v.machine_name}</td>
                    <td style={styleAllBorders}>{v.request_user_}</td>
                    <td style={styleAllBorders}>{v.request_user_code}</td>
                    <td style={styleAllBorders}>{v.request_user_name}</td>
                    <td style={styleAllBorders}>{v.request_dept_name}</td>
                    <td style={styleAllBorders}>{v.request_time}</td>
                    <td style={styleAllBorders}>{v.request_cause}</td>
                    <td style={styleAllBorders}>{v.request_time}</td>
                    <td style={styleAllBorders}>{v.request_work_type}</td>
                    <td style={styleAllBorders}>{v.request_equipment_type}</td>
                    <td style={styleAllBorders}>{v.request_equipment_type_other}</td>
                    <td style={styleAllBorders}>{v.repair_time}</td>
                    <td style={styleAllBorders}>{v.finish_user_code}</td>
                    <td style={styleAllBorders}>{v.finish_user_name}</td>
                    <td style={styleAllBorders}>{v.finish_time}</td>
                    <td style={styleAllBorders}>{v.finish_cause}</td>
                    <td style={styleAllBorders}>{v.finish_detail}</td>
                    <td style={styleAllBorders}>{v.finish_comment}</td>
                    <td style={styleAllBorders}>{v.finish_work_type}</td>
                    <td style={styleAllBorders}>{v.finish_work_type_other}</td>
                    <td style={styleAllBorders}>{v.finish_protect}</td>
                    <td style={styleAllBorders}>{v.finish_protect_detail}</td>
                </tr>
            )

        });

        return (
            <Container fluid style={{ backgroundColor: '#ffffff', minHeight: '100vh', minWidth: '100vw' }}>
                <Row>
                    <Col>
                        <div style={{ float: 'right' }}>
                            <ReactHTMLTableToExcel

                                id="test-table-xls-button"
                                className="download-table-xls-button"
                                table="report"
                                filename="DailyReport"
                                sheet="daily1"
                                buttonText="Download as XLS" />
                        </div>
                    </Col>
                </Row>
                <table id="report" >
                    <thead>
                        <tr style={{ height: '24px' }}>
                            <th style={styleAllBorders}>CODE</th>
                            <th style={styleAllBorders}>LINE_NAME</th>
                            <th style={styleAllBorders}>MACHINE_CODE</th>
                            <th style={styleAllBorders}>MACHINE_NAME</th>
                            <th style={styleAllBorders}>REQUEST_USER_CODE</th>
                            <th style={styleAllBorders}>REQUEST_USER_NAME</th>
                            <th style={styleAllBorders}>REQUEST_DEPT_NAME</th>
                            <th style={styleAllBorders}>REQUEST_TIME</th>
                            <th style={styleAllBorders}>REQUEST_CAUSE</th>
                            <th style={styleAllBorders}>REQUEST_WORK_TYPE</th>
                            <th style={styleAllBorders}>REQUEST_EQUIPMENT_TYPE</th>
                            <th style={styleAllBorders}>REQUEST_EQUIPMENT_TYPE_OTHER</th>
                            <th style={styleAllBorders}>REPAIR_TIME</th>
                            <th style={styleAllBorders}>FINISH_USER_CODE</th>
                            <th style={styleAllBorders}>FINISH_USER_NAME</th>
                            <th style={styleAllBorders}>FINISH_TIME</th>
                            <th style={styleAllBorders}>FINISH_CAUSE</th>
                            <th style={styleAllBorders}>FINISH_DETAIL</th>
                            <th style={styleAllBorders}>FINISH_COMMENT</th>
                            <th style={styleAllBorders}>FINISH_WORK_TYPE</th>
                            <th style={styleAllBorders}>FINISH_WORK_TYPE_OTHER</th>
                            <th style={styleAllBorders}>FINISH_PROTECT</th>
                            <th style={styleAllBorders}>FINISH_PROTECT_DETAIL</th>
                        </tr>

                    </thead>
                    <tbody>
                        {jobs}
                    </tbody>
                </table>

            </Container >
        )
    }
}

